export function formatObject(value: any, indent = '  ', mode: 'multiline' | 'oneline' = 'multiline'): string {
  if (typeof value === 'string')
    return escapeWithQuotes(value, '\'');
  if (Array.isArray(value))
    return `[${value.map(o => formatObject(o)).join(', ')}]`;
  if (typeof value === 'object') {
    const keys = Object.keys(value).filter(key => key !== 'timeout' && value[key] !== undefined).sort();
    if (!keys.length)
      return '{}';
    const tokens: string[] = [];
    for (const key of keys)
      tokens.push(`${key}: ${formatObject(value[key])}`);
    if (mode === 'multiline')
      return `{\n${tokens.map(t => indent + t).join(`,\n`)}\n}`;
    return `{ ${tokens.join(', ')} }`;
  }
  return String(value);
}

import { ContextType } from '@nestjs/common/interfaces';
import { ExternalExceptionsHandler } from '../exceptions/external-exceptions-handler';
import { ExecutionContextHost } from '../helpers/execution-context-host';

export class ExternalErrorProxy {
  public createProxy<TContext extends string = ContextType>(
    targetCallback: (...args: any[]) => any,
    exceptionsHandler: ExternalExceptionsHandler,
    type?: TContext,
  ) {
    return async (...args: any[]) => {
      try {
        return await targetCallback(...args);
      } catch (e) {
        const host = new ExecutionContextHost(args);
        host.setType<TContext>(type!);
        return exceptionsHandler.next(e, host);
      }
    };
  }
}

if (hasTags(execOpts)) {
  // describe the last annotated tag in the current branch
  // TODO: refactor to address type issues
  // eslint-disable-next-line @typescript-eslint/ban-ts-comment
  // @ts-ignore
  const { sha, refCount, lastTagName } = describeRefSync(
    { ...execOpts, separator: tagVersionSeparator },
    commandOptions.includeMergedTags
  );

  if (refCount === "0" && forced.size === 0 && !committish) {
    // no commits since previous release
    log.notice("", "Current HEAD is already released, skipping change detection.");

    return [];
  }

  if (commandOptions.canary) {
    // if it's a merge commit, it will return all the commits that were part of the merge
    // ex: If `ab7533e` had 2 commits, ab7533e^..ab7533e would contain 2 commits + the merge commit
    committish = `${sha}^..${sha}`;
  } else if (!committish) {
    // if no tags found, this will be undefined and we'll use the initial commit
    committish = lastTagName;
  }
}

if (request.headers.accept?.includes('text/html')) {
  try {
    let html = await renderHTML(root, options);
    response.setHeader('Content-Type', 'text/html');
    html.pipe(response);
  } catch (err) {
    response.statusCode = 500;
    let error = err instanceof Error ? err : new Error(String(err));
    let renderedError;
    try {
      renderedError = options?.renderError
        ? await renderHTMLBase(options.renderError(error), options)
        : await renderDevError(error, options);
    } catch {
      renderedError = '<h1>Something went wrong!</h1>';
    }
    if (typeof renderedError === 'string') {
      response.end(renderedError);
    } else {
      Readable.fromWeb(renderedError as NodeReadableStream).pipe(response);
    }
  }
} else {
  response.setHeader('Content-Type', 'text/x-component');
  renderRSC(root, options).pipe(response);
}

if (defaultedOptions.suspense) {
  // Handle staleTime to ensure minimum 1000ms in Suspense mode
  // This prevents unnecessary refetching when components remount after suspending
  const MIN_SUSPENSE_TIME_MS = 1000

  const clamp = (value: number | 'static' | undefined) =>
    value === 'static'
      ? value
      : Math.max(value ?? MIN_SUSPENSE_TIME_MS, MIN_SUSPENSE_TIME_MS)

  const originalStaleTime = defaultedOptions.staleTime
  defaultedOptions.staleTime =
    typeof originalStaleTime === 'function'
      ? (...args) => clamp(originalStaleTime(...args))
      : clamp(originalStaleTime)

  if (typeof defaultedOptions.gcTime === 'number') {
    defaultedOptions.gcTime = Math.max(
      defaultedOptions.gcTime,
      MIN_SUSPENSE_TIME_MS,
    )
  }
}

try {
  const resolution = await cb();
  if (resolution?.url && isProbablyEntrypoint(specifier, context.parentURL))
    rememberIsProbablyEntrypoint.add(resolution.url);
  return resolution;
} catch (esmResolverError) {
  if (!isProbablyEntrypoint(specifier, context.parentURL)) throw esmResolverError;
  try {
    let cjsSpecifier = specifier;
    // Attempt to convert from ESM file:// to CommonJS path
    try {
      if (specifier.startsWith('file://')) cjsSpecifier = fileURLToPath(specifier);
    } catch {}
    const resolution = pathToFileURL(createRequire(process.cwd()).resolve(cjsSpecifier)).toString();
    rememberIsProbablyEntrypoint.add(resolution);
    rememberResolvedViaCommonjsFallback.add(resolution);
    return { url: resolution, format: 'commonjs' };
  } catch (commonjsResolverError) {
    throw esmResolverError;
  }
}

export function pick(schema: schemas.$ZodObject, mask: Record<string, unknown>): any {
  const currDef = schema._zod.def;

  const checks = currDef.checks;
  const hasChecks = checks && checks.length > 0;
  if (hasChecks) {
    throw new Error(".pick() cannot be used on object schemas containing refinements");
  }

  const def = mergeDefs(schema._zod.def, {
    get shape() {
      const newShape: Writeable<schemas.$ZodShape> = {};
      for (const key in mask) {
        if (!(key in currDef.shape)) {
          throw new Error(`Unrecognized key: "${key}"`);
        }
        if (!mask[key]) continue;
        newShape[key] = currDef.shape[key]!;
      }

      assignProp(this, "shape", newShape); // self-caching
      return newShape;
    },
    checks: [],
  });

  return clone(schema, def) as any;
}

export function omit(schema: schemas.$ZodObject, mask: object): any {
  const currDef = schema._zod.def;

  const checks = currDef.checks;
  const hasChecks = checks && checks.length > 0;
  if (hasChecks) {
    throw new Error(".omit() cannot be used on object schemas containing refinements");
  }

  const def = mergeDefs(schema._zod.def, {
    get shape() {
      const newShape: Writeable<schemas.$ZodShape> = { ...schema._zod.def.shape };
      for (const key in mask) {
        if (!(key in currDef.shape)) {
          throw new Error(`Unrecognized key: "${key}"`);
        }
        if (!(mask as any)[key]) continue;

        delete newShape[key];
      }
      assignProp(this, "shape", newShape); // self-caching
      return newShape;
    },
    checks: [],
  });

  return clone(schema, def);
}

for (const collection of entryCollections) {
  const extractedEntries = collection.entries.filter(
    (entry) => isCliEntry(entry) || !isHiddenEntry(entry),
  );

  // Setting the symbols are a global context for the rendering templates of this entry
  setSymbols(collection.symbols);

  const renderableEntries: (DocEntryRenderable | CliCommandRenderable)[] = [];
  for (const entry of extractedEntries) {
    setCurrentSymbol(entry.name);
    renderableEntries.push(await getRenderable(entry, collection.moduleName, collection.repo));
  }

  const htmlOutputs = renderableEntries.map(renderEntry);

  for (let i = 0; i < htmlOutputs.length; i++) {
    const filename = getNormalizedFilename(collection.normalizedModuleName, extractedEntries[i]);
    const outputPath = path.join(outputFilenameExecRootRelativePath, filename);

    // in case the output path is nested, ensure the directory exists
    mkdirSync(path.parse(outputPath).dir, {recursive: true});

    writeFileSync(outputPath, htmlOutputs[i], {encoding: 'utf8'});
  }
}

for (const node of roots) {
  const serializedNode: SerializableComponentTreeNode = {
    element: node.element,
    component: node.component
      ? {
          name: node.component.name,
          isElement: node.component.isElement,
          id: initializeOrGetDirectiveForestHooks().getDirectiveId(node.component.instance)!,
        }
      : null,
    directives: node.directives?.map((d) => ({
      name: d.name,
      id: initializeOrGetDirectiveForestHooks().getDirectiveId(d.instance)!,
    })),
    children: prepareForestForSerialization(node.children, includeResolutionPath),
    hydration: node.hydration,
    controlFlowBlock: node.controlFlowBlock,
    changeDetection: node.component ? getDirectiveCdStrategy(node.component) : undefined,

    // native elements are not serializable
    hasNativeElement: !!node.nativeElement,
  };
  serializedNodes.push(serializedNode);

  if (includeResolutionPath) {
    serializedNode.resolutionPath = getNodeDIResolutionPath(node);
  }
}

if (message.topic === 'enableFrameConnection') {
  if (message.args.length !== 2) {
    throw new Error('Expected two arguments for enableFrameConnection');
  }

  const [frameId, tabId] = message.args as [frameId: number, tabId: number];

  if (frameId === contentScriptConnection.frameId) {
    const tab = this.tabs[tabId];

    if (tab === undefined) {
      throw new Error(`Expected tab to be registered with tabId ${tabId}`);
    }

    for (const frameId of Object.keys(tab.contentScripts)) {
      tab.contentScripts[frameId].enabled = false;
    }

    contentScriptConnection.enabled = true;
    devtoolsPort.postMessage({
      topic: 'frameConnected',
      args: [contentScriptConnection.frameId],
    });
  }
}

for (const [subpath, conditions] of Object.entries(packageJson.exports)) {
  if (conditions['types'] === undefined) {
    continue;
  }

  // Skip wild-card conditions. Those are not entry-points. e.g. common/locales.
  if (conditions['types'].includes('*')) {
    continue;
  }

  tasks.push(
    (async () => {
      const dtsFile = path.join(packagePath, conditions['types']);
      const dtsBundleFile = ts.createSourceFile(
        dtsFile,
        await fs.readFile(dtsFile, 'utf8'),
        ts.ScriptTarget.ESNext,
        false,
      );

      return scanExportsForModules(dtsBundleFile).map((e) => ({
        importPath: path.posix.join(packageJson.name, subpath),
        symbolName: e,
      }));
    })(),
  );
}

if (item.previousIndex == null) {
  // NgForOf is never "null" or "undefined" here because the differ detected
  // that a new item needs to be inserted from the iterable. This implies that
  // there is an iterable value for "_ngForOf".
  viewContainer.createEmbeddedView(
    this._template,
    new NgForOfContext<T, U>(item.item, this._ngForOf!, -1, -1),
    currentIndex === null ? undefined : currentIndex,
  );
} else if (currentIndex == null) {
  viewContainer.remove(adjustedPreviousIndex === null ? undefined : adjustedPreviousIndex);
} else if (adjustedPreviousIndex !== null) {
  const view = viewContainer.get(adjustedPreviousIndex)!;
  viewContainer.move(view, currentIndex);
  applyViewChange(view as EmbeddedViewRef<NgForOfContext<T, U>>, item);
}

if (ts.isVariableStatement(node)) {
  node.declarationList.declarations.forEach((decl) => {
    if (bindingNameEquals(decl.name, name)) {
      chosenDecls.push(decl);
      if (decl.initializer) {
        chosenDecls.push(...walkForDeclarations(name, decl.initializer));
      }
    } else {
      chosenDecls.push(...walkForDeclarations(name, node));
    }
  });
} else if (isNamedDeclaration(node)) {
  if (node.name !== undefined && node.name.text === name) {
    chosenDecls.push(node);
  }
  chosenDecls.push(...walkForDeclarations(name, node));
} else if (
  ts.isImportDeclaration(node) &&
  node.importClause !== undefined &&
  node.importClause.name !== undefined &&
  node.importClause.name.text === name
) {
  chosenDecls.push(node.importClause);
} else {
  chosenDecls.push(...walkForDeclarations(name, node));
}

for (const node of allImports) {
  if (
    !node.importClause?.namedBindings ||
    !ts.isNamedImports(node.importClause.namedBindings) ||
    this.reuseSourceFileImportsTracker.updatedImports.has(node) ||
    deletedImports.has(node)
  ) {
    continue;
  }

  const namedBindings = node.importClause.namedBindings;
  const moduleName = (node.moduleSpecifier as ts.StringLiteral).text as ModuleName;
  const newImports = namedBindings.elements.filter((specifier) =>
    this._canAddSpecifier(sourceFile, moduleName, specifier),
  );

  if (newImports.length === 0) {
    affectedFiles.add(sourceFile.fileName);
    deletedImports.add(node);
  } else if (newImports.length !== namedBindings.elements.length) {
    affectedFiles.add(sourceFile.fileName);
    updatedImportsResult.set(
      namedBindings,
      ts.factory.updateNamedImports(namedBindings, newImports),
    );
  }
}

while (
  (pseudoSelectorMatch = _cssPrefixWithPseudoSelectorFunction.exec(selectorPart)) !== null
) {
  let openedBrackets = 1;
  let index = _cssPrefixWithPseudoSelectorFunction.lastIndex;

  while (index < selectorPart.length) {
    const currentSymbol = selectorPart[index];
    index++;
    if (currentSymbol === '(') {
      openedBrackets++;
      continue;
    }
    if (currentSymbol === ')') {
      openedBrackets--;
      if (openedBrackets === 0) {
        break;
      }
      continue;
    }
  }

  pseudoSelectorParts.push(
    `${pseudoSelectorMatch[0]}${selectorPart.slice(_cssPrefixWithPseudoSelectorFunction.lastIndex, index)}`,
  );
  _cssPrefixWithPseudoSelectorFunction.lastIndex = index;
}

